import os
import json
import argparse
import heapq
import math
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start or prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128, decay=32.0):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()
    last_pos = None
    repeat_count = 0
    visited_count = {}

    for step in range(max_steps):
        neighbors = obs['neighbors']
        nodes = obs['nodes']
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        # Score: utility * exp(-d/decay)
        best_score = -1.0
        best_target = -1
        for i, nd in enumerate(nodes):
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            score = u * math.exp(-d / decay)
            if score > best_score:
                best_score = score
                best_target = i

        chosen = None
        if best_target >= 0:
            if best_target == start_idx:
                node_dict = {tuple(np.round(np.array(n['coords']), 2)): n for n in nodes}
                best_u = -1
                for nb in neighbors:
                    nt = tuple(np.round(np.array(nb), 2))
                    info = node_dict.get(nt)
                    u = info['utility'] if info else 0
                    if u > best_u:
                        best_u = u
                        chosen = nb
                if chosen is None:
                    chosen = neighbors[0]
            else:
                next_idx = path_first_step(prev, start_idx, best_target)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
        else:
            # Fallback: go to nearest unvisited node
            node_dict = {tuple(np.round(np.array(n['coords']), 2)): n for n in nodes}
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                unvisited = [nb for nb in neighbors if not node_dict.get(tuple(np.round(np.array(nb), 2)), {}).get('visited', False)]
                chosen = unvisited[0] if unvisited else neighbors[0]

        # Anti-oscillation: track visited counts
        ckey = tuple(np.round(np.array(chosen), 1))
        visited_count[ckey] = visited_count.get(ckey, 0) + 1
        if visited_count[ckey] >= 3 and len(neighbors) > 1:
            others = [nb for nb in neighbors if tuple(np.round(np.array(nb), 1)) != ckey]
            if others:
                # pick least visited among others
                others.sort(key=lambda c: visited_count.get(tuple(np.round(np.array(c), 1)), 0))
                chosen = others[0]

        obs, info = env.step(chosen)
        if info['done']:
            break

    return env.get_metrics()


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=True)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    with open(cfg_path) as f:
        cfg = json.load(f)

    eval_maps_dir = os.path.join(args.data_path, 'maps_eval')
    episodes = cfg.get('episodes') or cfg.get('maps') or []

    if not episodes:
        episodes = []
        for env_type in ['room', 'tunnel', 'outdoor']:
            sub = os.path.join(eval_maps_dir, env_type)
            if os.path.isdir(sub):
                for f in sorted(os.listdir(sub)):
                    if f.endswith('.png'):
                        episodes.append({'map_path': f'{env_type}/{f}', 'env_type': env_type})

    per_episode = []
    type_results = {}
    for ep in episodes:
        mp = ep['map_path'] if isinstance(ep, dict) else ep
        env_type = ep.get('env_type') if isinstance(ep, dict) else mp.split('/')[0]
        full = os.path.join(eval_maps_dir, mp)
        try:
            m = plan_episode(full)
            success = 1 if m['explored_rate'] > 0.9999 else 0
            per_episode.append({
                'map_path': mp, 'env_type': env_type,
                'success': success,
                'travel_distance': float(m['travel_distance']),
                'explored_rate': float(m['explored_rate']),
            })
            type_results.setdefault(env_type, []).append((m, success))
        except Exception as e:
            print(f'Error on {mp}: {e}')
            per_episode.append({'map_path': mp, 'env_type': env_type, 'success': 0, 'travel_distance': 0.0, 'explored_rate': 0.0})

    explored_rate_mean = float(np.mean([e['explored_rate'] for e in per_episode])) if per_episode else 0.0
    succ_dists = [e['travel_distance'] for e in per_episode if e['success']]
    travel_mean = float(np.mean(succ_dists)) if succ_dists else 0.0
    success_rate = float(np.mean([e['success'] for e in per_episode])) if per_episode else 0.0

    per_type = {}
    for t, lst in type_results.items():
        ms = [x[0] for x in lst]
        ss = [x[1] for x in lst]
        succ_d = [m['travel_distance'] for m, s in lst if s]
        per_type[t] = {
            'explored_rate': float(np.mean([m['explored_rate'] for m in ms])),
            'travel_distance': float(np.mean(succ_d)) if succ_d else 0.0,
            'success_rate': float(np.mean(ss)),
        }

    out = {
        'explored_rate': explored_rate_mean,
        'travel_distance': travel_mean,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': len(per_episode),
    }
    with open(args.output, 'w') as f:
        json.dump(out, f)
    print(f'Wrote {args.output}: success_rate={success_rate:.3f}, explored={explored_rate_mean:.3f}, travel={travel_mean:.1f}')


if __name__ == '__main__':
    main()
